app = Flask(__name__)
DATA_DIR = 'data'

# Utility functions to load data

def load_songs():
    songs = []
    path = os.path.join(DATA_DIR, 'songs.txt')
    if not os.path.exists(path):
        return songs
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            fields = line.split('|')
            # 1. song_id (int), 2. title (str), 3. artist_id (int), 4. album_id (int), 5. genre (str), 6. duration (int), 7. release_date (str), 8. play_count (int)
            if len(fields) != 8:
                continue
            try:
                song_id = int(fields[0])
                title = fields[1]
                artist_id = int(fields[2])
                album_id = int(fields[3])
                genre = fields[4]
                duration = int(fields[5])
                release_date = fields[6]
                play_count = int(fields[7])
            except ValueError:
                continue
            songs.append({
                'song_id': song_id,
                'title': title,
                'artist_id': artist_id,
                'album_id': album_id,
                'genre': genre,
                'duration': duration,
                'release_date': release_date,
                'play_count': play_count
            })
    return songs


